scwin.f_CheckFileExt = async function (ext, path) {
  ext = ext.toUpperCase();
  path = path.toUpperCase();
  let elen = ext.length;
  let flen = path.length;
  return ext == path.substring(flen - elen, flen);
};
scwin.f_Retrieve = async function () {
  scwin.f_ProcessBinding();
  if (dma_condition.get("rsltsStdDtSt") == "" || dma_condition.get("rsltsStdDtEnd") == "") {
    await $c.win.alert($p, "실적기간은 필수 입력 항목입니다.");
    return false;
  }
  if (!$c.gus.cfIsAfterDate($p, dma_condition.get("rsltsStdDtSt"), dma_condition.get("rsltsStdDtEnd"))) {
    await $c.gus.cfAlertMsg($p, MSG_CM_ERR_039);
    return;
  }
  await $c.sbm.execute($p, sbm_retrieve);
};
scwin.f_ProcessBinding = async function () {
  dma_condition.set("homeClntNo", ed_homeClntNo.getValue());
  dma_condition.set("clntNo", ed_clntNo.getValue());
  dma_condition.set("rsltsStdDtSt", ica_rsltsStdDtSt.getValue());
  dma_condition.set("rsltsStdDtEnd", ica_rsltsStdDtEnd.getValue());
  dma_condition.set("vehclNo", txt_vehclNo.getValue());
};
scwin.f_Save = async function () {
  let checkedCnt = 0;
  for (let i = 0; i < ds_results.getRowCount(); i++) {
    if (ds_results.getRowStatus(i) == "C") {
      if (!$c.gus.cfValidateValue($p, ds_results.getCellData(i, "rsltsStdDt"), "date=YYYYMMDD")) {
        await $c.gus.cfAlertMsg($p, i + 1 + "번째 데이터의 실적일자는 유효한 날짜 형식이 아닙니다.");
        return;
      }
      if (ds_results.getCellData(i, "rsltsStdDt") == "") {
        await $c.win.alert($p, i + 1 + "행의 실적일자는 필수 입력 항목 입니다.");
        return false;
      }
      if (ds_results.getCellData(i, "vehclNo") == "") {
        await $c.win.alert($p, i + 1 + "행의 차량번호는 필수 입력 항목 입니다.");
        return false;
      }
      if (ds_results.getCellData(i, "homeClntNo") == "") {
        await $c.win.alert($p, i + 1 + "행의 소속거래처는 필수 입력 항목 입니다.");
        return false;
      }
      if (ds_results.getCellData(i, "clntNo") == "" && ds_results.getCellData(i, "clntNm") == "") {
        await $c.win.alert($p, i + 1 + "행의 매니저코드/명  중 하나는 필수 입력 항목 입니다.");
        return false;
      }
      checkedCnt++;
    }
    if (ds_results.getRowStatus(i) == "U") {
      checkedCnt++;
    }
  }
  if (checkedCnt == 0) {
    await $c.win.alert($p, "저장 할 데이터가 없습니다.");
    return false;
  }
  let chk = await $c.win.confirm($p, MSG_CM_CRM_001);
  if (chk) {
    await $c.sbm.execute($p, sbm_save);
  }
};
scwin.f_Apply = async function () {
  let checkedCnt = 0;
  for (let i = 0; i < ds_results.getRowCount(); i++) {
    if (ds_results.getRowStatus(i) == "U") {
      if (ds_results.getCellData(i, "uploadNo") == "") {
        await $c.win.alert($p, "업로드 후 적용해주세요");
        return;
      }
      if (ds_results.getCellData(i, "rsltsMgntNo") != "") {
        await $c.win.alert($p, "적용된 데이터는 재 적용할 수 없습니다.");
        return;
      }
      checkedCnt++;
    }
  }
  if (checkedCnt == 0) {
    await $c.win.alert($p, "적용 할 데이터가 없습니다.");
    return false;
  }
  let chk = await $c.win.confirm($p, "업로드 한 운송임을 등록하시겠습니까?");
  if (chk) {
    await $c.sbm.execute($p, sbm_apply);
  }
};
