scwin.f_openCommonPopUp = function (disGubun, pCode, pName, pClose, pAllSearch, row) {
  switch (disGubun) {
    case 1:
      let condition1 = "";
      if (cnd_chb_repClntYn.getValue() != "") {
        condition1 = "RP";
      }
      udc_homeClnt.ilCommonPopUp(scwin.callbackHomeClnt, pCode, pName, pClose, '5', null, '150,170', null, condition1, null, null, null, null, null, pAllSearch, "거래처,거래처코드,거래처명");
      break;
    case 2:
      let pCode2 = ed_selpchItemCd ? ed_selpchItemCd.getValue() : pCode;
      let pName2 = txt_selpchItemNm ? txt_selpchItemNm.getValue() : pName;
      // TODO: ed_selpchItemCd / txt_selpchItemNm 은 검색조건 영역에 없으므로 UDC 또는 별도 컴포넌트 필요
      udc_homeClnt.ilCommonPopUp(scwin.callbackSelpchItem, pCode2, pName2, 'T', null, null, null, null, ',,,,,,', null, null, null, null, null, null, null);
      break;
    case 3:
      udc_vehclNo.ilCommonPopUp(scwin.callbackVehclNo, pCode, pName, pClose, null, null, null, null, null, "400", null, null, null, null, 'T', "차량번호,차량단축코드,차량번호");
      break;
    case 4:
      udc_vehclNo.ilCommonPopUp(function (rtnList) {
        scwin.callbackGridVehclNo(rtnList, row);
      }, pCode, pName, pClose, null, null, null, null, null, "400", null, null, null, null, 'T', "차량번호,차량단축코드,차량번호");
      break;
    case 5:
      udc_homeClnt.ilCommonPopUp(function (rtnList) {
        scwin.callbackGridHomeClnt(rtnList, row);
      }, pCode, pName, 'T', '5', null, '150,170', null, null, null, null, null, null, null, 'T', "거래처,거래처코드,거래처명");
      break;
    case 6:
      udc_clnt.ilCommonPopUp(function (rtnList) {
        scwin.callbackGridClnt(rtnList, row);
      }, pCode, pName, 'T', '5', null, '150,170', null, null, null, null, null, null, null, 'T', "거래처,거래처코드,거래처명");
      break;
    case 7:
      udc_homeClnt.ilCommonPopUp(function (rtnList) {
        scwin.callbackGridSelpchItem(rtnList, row);
      }, pCode, pName, 'T', null, null, null, null, ',,,,,,', null, null, null, null, null, null, null);
      break;
    default:
      break;
  }
};
